import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Method;

import org.apache.commons.csv.CSVParser;
import org.apache.commons.csv.Lexer;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

class CSVParserTest {

    @Mock
    private Lexer lexerMock;

    private CSVParser csvParser;

    @BeforeEach
    void setUp() throws Exception {
        MockitoAnnotations.openMocks(this);
        // Create CSVParser instance with a stub constructor using reflection since no public constructor with Lexer
        csvParser = (CSVParser) java.lang.reflect.Proxy.newProxyInstance(
                CSVParser.class.getClassLoader(),
                new Class[] { CSVParser.class },
                (proxy, method, args) -> null);

        // Use reflection to set the private final lexer field
        var lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(csvParser, lexerMock);
    }

    @Test
    void testGetFirstEndOfLine_ReturnsExpectedValue() {
        String expectedEol = "\n";
        when(lexerMock.getFirstEol()).thenReturn(expectedEol);

        String actualEol = csvParser.getFirstEndOfLine();

        assertEquals(expectedEol, actualEol);
        verify(lexerMock).getFirstEol();
    }
}
